{
  "family": "Wolff-Kishner Reduction",
  "candidate": {
    "substrate_smiles": [
      "CCC(=O)CC"
    ],
    "product_smiles": [
      "CCCCC"
    ],
    "optional_reagent_smiles": [
      "NN",
      "[OH-].[K+]"
    ],
    "rationale": "This reaction shows the reduction of a simple, acyclic, aliphatic ketone (3-pentanone) to its corresponding alkane (n-pentane). This is a classic textbook example of the Wolff-Kishner reduction, clearly demonstrating the conversion of a carbonyl group to a methylene group under basic conditions using hydrazine and potassium hydroxide. The substrate is simple and avoids complex functional groups or aromatic rings that could cause collisions with other named reactions.",
    "collision_avoidance_note": "The substrate is a simple aliphatic ketone, avoiding aromatic rings (which could trigger Clemmensen reduction or Friedel-Crafts type reactions), esters (avoiding Claisen condensation), or other reducible functional groups. The transformation is a direct C=O to CH2 conversion, which is the defining feature of the Wolff-Kishner reduction, minimizing overlap with other deoxygenation or reduction reactions that have different specificities."
  }
}
